window.__QUIZ_DATA__=[{"id":"objective>Mathematics>2000>1","subject":"Mathematics","year":"2000","type":"Objective","topic":"NUMBER AND NUMERATION : PERCENTAGES","question":"Express 7/19 as a percentage, correct to 1 decimal place","images":[],"options":{"A":"2.7%","B":"3.7%","C":"27.1%","D":"36.8%"},"answer":"D","explanation":"719asapercentage  719\u00d7100%  =70019=36.84% to one decimal place = 36.8%","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>2","subject":"Mathematics","year":"2000","type":"Objective","topic":"NUMBER AND NUMERATION : NUMBERS IN STANDARD FORM-SCIENTIFIC NOTATION","question":"Express 398753 to three significant figures","images":[],"options":{"A":"398000","B":"398700","C":"398800","D":"399000"},"answer":"D","explanation":"398753 to three significant figures = 399,000    Therefore, 398753 = 399,000 (to 3 s.f)","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>3","subject":"Mathematics","year":"2000","type":"Objective","topic":"NUMBER AND NUMERATION : SURDS -RADICALS","question":"Simplify 10/\u221a32","images":[],"options":{"A":"5/4 \u221a2","B":"4/5\u221a2","C":"5/16\u221a2","D":"16/5\u221a2"},"answer":"A","explanation":"10&radic;32&nbsp;=10&radic;16&nbsp;\u00d7&radic;2&nbsp;=104&radic;2&nbsp;=52&radic;2&nbsp;  rationalizing  52&radic;2&nbsp;\u00d7&radic;2&nbsp;&radic;2&nbsp;=5&radic;2&nbsp;2\u00d72=5&radic;2&nbsp;4","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>4","subject":"Mathematics","year":"2000","type":"Objective","topic":"NUMBER AND NUMERATION : NUMBER BASES","question":"Find the missing number in the addition of the following numbers in base seven    4 3 2 1  1 2 3 4  *  *  *  *  ---------  1 2 3 4 1  ---------","images":[],"options":{"A":"3453","B":"5556","C":"6016","D":"13453"},"answer":"A","explanation":"To get the missing number, we add the two together,  4 3 2 1  1 2 3 4  ---------  5 5 5 5  ---------  subtract from the answer   1 2 3 4 1     5 5 5 5  -----------     3 4 5 37","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2000>5","subject":"Mathematics","year":"2000","type":"Objective","topic":"NUMBER AND NUMERATION : FRACTIONS, DECIMALS AND APPROXIMATIONS","question":"What fraction must be subtracted from the sum of 21/6 and 27/12 to give 31/4?","images":[],"options":{"A":"1/3","B":"1/2","C":"1 1/6","D":"1 1/2"},"answer":"D","explanation":"216+2712-X=314  2612+3112-X=3912  5712-3912=X  X=1812=112","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>6","subject":"Mathematics","year":"2000","type":"Objective","topic":"NUMBER AND NUMERATION : LAWS OF INDICES","question":"Simplify(1681)-3/4\u00d7\u221a10081","images":[],"options":{"A":"80243","B":"2027","C":"256","D":"154"},"answer":"D","explanation":"(1681)-3/4\u00d7&radic;10081&nbsp;  applying laws of indices   =(8116)3/4\u00d7109  =(sqr4(8116))3\u00d7109  =(32)3\u00d7109  =278\u00d7109=154","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2000>7","subject":"Mathematics","year":"2000","type":"Objective","topic":"NUMBER AND NUMERATION : NUMBER BASES","question":"Which of the following numbers is a perfect cube?","images":[],"options":{"A":"350","B":"504","C":"950","D":"1728"},"answer":"D","explanation":"1728 = 12 \u00d7 12 \u00d7 12 = 123  A perfect cube is any number that can be expressed in the form x3, where X is a real number.","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>8","subject":"Mathematics","year":"2000","type":"Objective","topic":"ALGEBRAIC PROCESSES : BINARY OPERATIONS","question":"If 104x = 68, find the value of x.","images":[],"options":{"A":"5","B":"7","C":"8","D":"9"},"answer":"C","explanation":"104x = 68  104x = 1(x2) + 0(x)1 + 4(x)0 = 68  x2 + 4 = 68  x2 = 68 - 4  x2 = 64  squaring both sides  &radic;x2&nbsp; = &radic;64&nbsp;  x = \u00b18","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2000>9","subject":"Mathematics","year":"2000","type":"Objective","topic":"NUMBER AND NUMERATION : RATIO, PROPORTIONS AND RATES","question":"The age of three men are in the ratio of 3:4:5 if the difference between the ages of the oldest and youngest is 18 years, find the sum of the ages of three men.","images":[],"options":{"A":"45 years","B":"72 years","C":"108 years","D":"216 years"},"answer":"C","explanation":"Ratio = 3 : 4 : 5  let the actual ages be 3x, 4x and 5x  5x - 3x = 18  2x = 18  x=182  x = 9    Sum of there ages, = 3x + 4x + 5x  substituting 9 for x in the equation  3(9) + 4(9) + 5(9)  27 + 36 + 45  108 yrs","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>10","subject":"Mathematics","year":"2000","type":"Objective","topic":"NUMBER AND NUMERATION : LOGARITHMS","question":"Given that log4X  = -3, Find The x.","images":[],"options":{"A":"1/81","B":"1/64","C":"64","D":"81"},"answer":"B","explanation":"Log4x = -3  Using the Log rule,  LogaX = y, X = ay  X=4-3=164","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>11","subject":"Mathematics","year":"2000","type":"Objective","topic":"NUMBER AND NUMERATION : LOGARITHMS","question":"Given that the logarithm of a number is 1.8732, find correct to 2 significant figure, the square root of the number","images":[],"options":{"A":"0.29","B":"0.75","C":"0.86","D":"0.93"},"answer":"C","explanation":"Log10X = 1\u0305.8732  Using log rule LogaX = Y, X = ay  since  log10X = 1\u0305.8732  log10&radic;x&nbsp;=1\u0305.87322  =2\u0305 + 1.87322 = 1\u0305.9366  The anti-log is   &radic;d&nbsp; = Antilog (1\u0305.9366)  d = 0.86","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>12","subject":"Mathematics","year":"2000","type":"Objective","topic":"NUMBER AND NUMERATION : RATIO, PROPORTIONS AND RATES","question":"A car moves at an average speed of 30kmh-1, how long does it takes to cover 200 meters ?","images":[],"options":{"A":"2.4sec","B":"24sec","C":"144 sec","D":"240 sec"},"answer":"B","explanation":"30Kmh-1 means 30Km/hr = 30(1000m)/h  \u21d2 30,000m in 1hr  Therefore,  1m=130,000hr  200=(130,000\u00d7200hr)=1150hrs=3600150 = 24 sec","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>13","subject":"Mathematics","year":"2000","type":"Objective","topic":"NUMBER AND NUMERATION : DISCOUNT, COMMISION AND HIRE PURCHASE","question":"A man bought a television set on a hire purchase for \u20a625,000 out of which he paid \u20a610,000 . if he is allowed to pay the the balance in eight equal installment, find out the value of each installment","images":[],"options":{"A":"\u20a61250","B":"\u20a61578","C":"\u20a61875","D":"\u20a63125"},"answer":"C","explanation":"\u20a625,000 on hire purchase   He first paid \u20a610,000  Balance = \u20a625,000 - \u20a610,000  Balance = \u20a615,000    Paying in 8 instalments,  eachinstalment=15,0008=\u20a61,875","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>14","subject":"Mathematics","year":"2000","type":"Objective","topic":"TRIGONOMETRY : BEARINGS","question":"A tree is 8km due south of a building . kofi is standing 8km west of the tree. use this to answer the questions    How far is kofi from the building","images":[],"options":{"A":"4\u221a2","B":"8km","C":"8\u221a2 km","D":"16km"},"answer":"C","explanation":"x2 = 82 + 82  x2 = 64 + 64 = 128  x2 = 128  squaring both sides  x = 8&radic;2&nbsp;km","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>15","subject":"Mathematics","year":"2000","type":"Objective","topic":"TRIGONOMETRY : BEARINGS","question":"A tree is 8km due south of a building . kofi is standing 8km west of the tree. use this to answer the questions  Find the bearing of kofi from the building.","images":[],"options":{"A":"315\u2218","B":"270\u2218","C":"225\u2218","D":"135\u2218"},"answer":"C","explanation":"Kofi is in SW direction with respect to the building   let the angle be *alpha8  tan\u03b1 = 8/8 = 1  \u03b1 = tan-1(1)  \u03b1 = 45\u00b0  Bearing = (180\u00b0 + 45\u00b0) = 225\u00b0","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>16","subject":"Mathematics","year":"2000","type":"Objective","topic":"TRIGONOMETRY : BEARINGS","question":"A tree is 8km due south of a building . kofi is standing 8km west of the tree. use this to answer the questions  Which of the following is equivalent to S50\u2218W","images":[],"options":{"A":"040\u2218","B":"130\u2218","C":"220\u2218","D":"230\u2218"},"answer":"D","explanation":"S50\u00b0W = (180 + 50)\u00b0 = 230\u00b0    230\u00b0 is equivalent to S50\u2218W","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>17","subject":"Mathematics","year":"2000","type":"Objective","topic":"TRIGONOMETRY : ANGLES OF ELEVATION AND DEPRESSION","question":"In the diagram , AB is a vertical pole and BC is horizontal. If |AC| = 10m and BC = 5m, calculate the angle of depression of C from A","images":["data:image/png;base64,"],"options":{"A":"63\u2218","B":"60\u2218","C":"45\u2218","D":"27\u2218"},"answer":"B","explanation":"Let the angle of depression of C  From A be \u03b2 as shown,  In \u0394ABC;  sin\u03b1=510  \u03b1 = sin-10.5  \u03b1 = 30\u00b0  \u03b1 + \u03b2 = 90\u00b0 (Complimentary angles)  \u03b2 = 90 - 30 = 60\u00b0","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>18","subject":"Mathematics","year":"2000","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"The bar chat show a distribution of marks scored by a group of student in a test.      How many student scored 4 above","images":["data:image/png;base64,"],"options":{"A":"15","B":"11","C":"10","D":"7"},"answer":"B","explanation":"From the chart,  number of students scoring 4 marks and above,  Freq = 4 + 2 + 2 + 0 + 1 + 1 + 1 = 11 students","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>19","subject":"Mathematics","year":"2000","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"The bar chat show a distribution of marks scored by a group of student in a test.    How many students took the test?","images":["data:image/png;base64,"],"options":{"A":"38","B":"22","C":"15","D":"11"},"answer":"B","explanation":"Total no of students that took the test = 1 + 3 + 2 + 5 + 11 = 22 students","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>20","subject":"Mathematics","year":"2000","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"Calculate the standard deviation of the following marks 2,3,6,2,5,0,4,2","images":[],"options":{"A":"1.5","B":"1.7","C":"1.8","D":"1.9"},"answer":"C","explanation":"XFFxdd2Fd20  2  3  4  5  61  3  1  1  1  10  6  3  4  5  6-3  -1  0  1  2  39  1  0  1  4  99  3  0  1  4  9824\u2211d2 = 26    x\u0304=\u2211Fx\u2211F=(248)=3  S.D=&radic;\u2211Fd2\u2211F&nbsp;=&radic;268&nbsp;=&radic;3.25&nbsp;=1.8","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2000>21","subject":"Mathematics","year":"2000","type":"Objective","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"The probability that kodjo and adoga pass an examination are 3/4and 3/5respectively.find the probability of both failing the examination.","images":[],"options":{"A":"1/10","B":"3/10","C":"9/20","D":"2/3"},"answer":"A","explanation":"Pr(Kodjopass)=34  Pr(Kodjofails)=1-34=14  Pr(Adogapasses)=35  Pr(Adogafail)=1 - 35  =25  Pr (both fails) = Pr(Adoga fails) \u00d7 Pr (Kodjo fails)  =14x25=110","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>22","subject":"Mathematics","year":"2000","type":"Objective","topic":"PLANE GEOMETRY : TRIANGLES AND POLYGONS","question":"Which of the following triangles are congruent","images":["data:image/png;base64,"],"options":{"A":"I and III only","B":"II and IV only","C":"i and II only","D":"II and III only"},"answer":"D","explanation":"Congruent means the same in all respect angle 50\u00b0 is included in II and III.","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>23","subject":"Mathematics","year":"2000","type":"Objective","topic":"PLANE GEOMETRY : TRIANGLES AND POLYGONS","question":"Which of the following statement is /are true about a rectangle   I. Each diagonal cut the rectangle in two congruent triangle  II. A rectangle has four lines of symmetry  III. The diagonals intersect at right angles","images":[],"options":{"A":"I and II only","B":"I only","C":"II only","D":"II and III only"},"answer":"B","explanation":"The Quadrilateral that has the diagonals intersecting at right angle is a rhombus and not a rectangle, also a rectangle has 2 lines of symmetry not 4. Therefore,II and III are not true","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>24","subject":"Mathematics","year":"2000","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"In the diagram,PQRS is a circle center O is a diameter and \u2220QSR","images":["data:image/png;base64,"],"options":{"A":"30\u2218","B":"40\u2218","C":"45\u2218","D":"50\u2218"},"answer":"D","explanation":"If P is joined to S,  PQRS = Cyclic quadrilateral       Since","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2000>25","subject":"Mathematics","year":"2000","type":"Objective","topic":"PLANE GEOMETRY : TRIANGLES AND POLYGONS","question":"Each sides of a regular convex polygon subtends an angle of 30\u2218 at it center. calculate each interior angle","images":[],"options":{"A":"75\u2218","B":"150\u2218","C":"160\u2218","D":"168\u2218"},"answer":"B","explanation":"Angle subtended at the centre by each state = 30\u00b0  Polygon has n sides   30n = 360  dividing both sides by 30  30n30n=36030  n = 12  The sum of all the interior angles of an n-sided polygon,  \u21d2 (2n - 4)90  \u21d2 [2(12) - 4]90  \u21d2 [24 - 4]90  \u21d2 20(90)  \u21d2 1800\u00b0  Eachinteriorangle=180012=150\u00b0","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>26","subject":"Mathematics","year":"2000","type":"Objective","topic":"PLANE GEOMETRY : TRIANGLES AND POLYGONS","question":"If the interior angles of a hexagon are 107\u2218,2x\u2218,150\u2218,95\u2218, (2x-5)\u2218 and 123\u2218, find x","images":[],"options":{"A":"57 1/2","B":"65\u2218","C":"106\u2218","D":"120\u2218"},"answer":"B","explanation":"Hexagon = 6-sided polygon  The sum of the interior angles of a polygon = (2n - 4)90  n \u21d2 6  \u21d2 2(6) - 4  \u21d2 12 - 4(90)  \u21d2 8(90)  \u21d2 720\u00b0    107\u00b0 + 2x + 150\u00b0 + 95 + (2x - 15)\u00b0 + 123 = 720\u00b0  230\u00b0 + 245\u00b0 + 4x - 15 = 720\u00b0  4x + 460\u00b0 = 720\u00b0  4x = 260  dividing both sides by 4  4x4=2604  x = 65\u00b0","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>27","subject":"Mathematics","year":"2000","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"In the diagram, POS and ROT are striaght lines, OPQR is a parallelogram, |OS| = |OT| and find \u2220OPQ","images":["data:image/png;base64,"],"options":{"A":"160\u2218","B":"140\u2218","C":"120\u2218","D":"100\u2218"},"answer":"D","explanation":"","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>28","subject":"Mathematics","year":"2000","type":"Objective","topic":"ALGEBRAIC PROCESSES : FORMULATION AND EVALUATION OF ALGEBRAIC PROCESSES","question":"Given that x = -1/2and y = 4, evaluate 3x2y + xy2","images":[],"options":{"A":"-5","B":"-1","C":"4","D":"11"},"answer":"A","explanation":"SinceX=-12,y=4  3x2y + xy2  \u21d23(-12)24+(-12)(4)2  \u21d23(14)4+(-12)16  \u21d2 3 - 8 = -5","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>29","subject":"Mathematics","year":"2000","type":"Objective","topic":"NUMBER AND NUMERATION : LAWS OF INDICES","question":"Given that 27(1+x) = 9 find x","images":[],"options":{"A":"-3","B":"-1/3","C":"5/3","D":"2"},"answer":"B","explanation":"271 + x = 9  33(1 + x) = 32  equating powers  3(1 + x) = 2  3 + 3x = 2  3x = 2 - 3  3x = -1  x=-13","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>30","subject":"Mathematics","year":"2000","type":"Objective","topic":"NUMBER AND NUMERATION : VARIATION","question":"If x varies inversely as y and x = 2/3; when y = 9, find the value of y when x = 3/4","images":[],"options":{"A":"1/18","B":"8/81","C":"9/2","D":"8"},"answer":"D","explanation":"Since x varies inversely as y  x\u03b11y  x=ky  23=k9  3k = 18  k=183  k = 6  x=6y  wheny=34  x=634  x=6 \u00d7 43=8","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2000>31","subject":"Mathematics","year":"2000","type":"Objective","topic":"ALGEBRAIC PROCESSES : EXPANSION AND FACTORISATION","question":"Given that (2x+7) is a factor of 2x2 + 3x - 14, find the other factor","images":[],"options":{"A":"x+2","B":"2-x","C":"x-2","D":"x+1"},"answer":"C","explanation":"2x2 + 3x - 14  2x2 + 7x - 4x - 14  x(2x + 7) - 2(2x + 7)  (x - 2)(2x + 7)  The other factor is (x - 2)","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>32","subject":"Mathematics","year":"2000","type":"Objective","topic":"ALGEBRAIC PROCESSES : ALGEBRAIC FRACTIONS","question":"Simplify1x-3-3(x-1)x2-9","images":[],"options":{"A":"x-1x-3","B":"-2x+3","C":"x-1x+3","D":"4xx2-9"},"answer":"B","explanation":"1x - 3-3(x - 1)x2 - 9  =1x - 3-3(x - 1)(x + 3)(x - 3)  x + 3 - 3x + 3(x + 3)(x - 3)  =-2x + 6(x - 3)(x + 3)  =-2(x - 3)(x - 3)(x + 3)=-2x + 3","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>33","subject":"Mathematics","year":"2000","type":"Objective","topic":"ALGEBRAIC PROCESSES : LINEAR INEQUALITIES","question":"Which of the following number lins represents the inequality 2\u2264x","images":["data:image/png;base64,","data:image/png;base64,","data:image/png;base64,","data:image/png;base64,"],"options":{"A":"","B":"","C":"","D":""},"answer":"A","explanation":"Since the interval is closed at -2 and open at 9    \u2234 -2 \u2264 x","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>34","subject":"Mathematics","year":"2000","type":"Objective","topic":"ALGEBRAIC PROCESSES : LINEAR INEQUALITIES","question":"For an inequality for a distance d meters which is more than 18m but not more than 23m","images":[],"options":{"A":"18\u2264d\u226423","B":"18","C":"18\u2264d","D":"d23"},"answer":"B","explanation":"d > 18cm  d \u2265 23m  Combining,  Therefore, 18","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>35","subject":"Mathematics","year":"2000","type":"Objective","topic":"ALGEBRAIC PROCESSES : QUADRATIC EQUATIONS","question":"find the equation whose roots are -8 and 5.","images":[],"options":{"A":"x2 + 13x + 40 = 0","B":"x2 - 13x - 40 = 0","C":"x2 - 3x + 40 = 0","D":"x2 + 3x - 40 = 0"},"answer":"D","explanation":"roots are -8, 5  Sum of Roots = (-8 + 5) = 3  Product of 11 = (-8 \u00d7 5) = -40  Equation = x2 - (sum of roots)x + products = 0  x2 - (-3x) + (-40) = 0  x2 + 3x - 40 = 0","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>36","subject":"Mathematics","year":"2000","type":"Objective","topic":"ALGEBRAIC PROCESSES : CHANGE OF SUBJECT OF A FORMULA/RELATION","question":"maketthesubjectoftheformulak=m\u221at - pr","images":[],"options":{"A":"rk2+pm2","B":"rk2+pm2m2","C":"rk2-pm2","D":"rk2-p2m2"},"answer":"B","explanation":"k=m &radic;t - pr&nbsp;  Squaring both sides  k2=m2(t - p)r  dividing both sides by m2  k2m2=t - pr  multiplying by r,  k2rm=t - p  adding P to both sides   k2rm+p=t  k2r+m2pm2=t","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>37","subject":"Mathematics","year":"2000","type":"Objective","topic":"ALGEBRAIC PROCESSES : QUADRATIC EQUATIONS","question":"solve the equation 3y2 = 27y","images":[],"options":{"A":"y = 0 or 3","B":"y = 0 or 9","C":"y = -3 or 3","D":"y = 3 or 9"},"answer":"B","explanation":"3y2 = 27y  3y2 - 27y = 0  3y(y - 9) = 0  3y = 0 or y - 9 = 0  y = 0 or 9","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>38","subject":"Mathematics","year":"2000","type":"Objective","topic":"ALGEBRAIC PROCESSES : ALGEBRAIC FRACTIONS","question":"Findthevalueofxsuchthattheexpression1x+43x-56x+1 = 0","images":[],"options":{"A":"1/6","B":"1/4","C":"-3/2","D":"-7/6"},"answer":"C","explanation":"1x+43x-56x+1  LCM is 6x  6+8-5+6x6x=0  9+6x6x  A fraction is 0 when numerator = 0  9 + 6x = 0  x=-96=-32  -32","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>39","subject":"Mathematics","year":"2000","type":"Objective","topic":"NUMBER AND NUMERATION : VARIATION","question":"Given that p varies directly as q varies while q varies inversely as r, which of the following statement is true","images":[],"options":{"A":"r varies directly as p","B":"p varies inversely as r","C":"p varies directly as r","D":"q varies inversely as p"},"answer":"B","explanation":"P \u03b1 q  q\u03b11r  p\u03b11r  P varies inversely as r","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>40","subject":"Mathematics","year":"2000","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"In the diagram, PQRS is a circle with center O.  RST is a tangent at S and \u2218. find","images":["data:image/png;base64,"],"options":{"A":"42\u2218","B":"48\u2218","C":"60\u2218","D":"66\u2218"},"answer":"B","explanation":"PQS=12(96)angleatcentre=2timesatcircumference","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>41","subject":"Mathematics","year":"2000","type":"Objective","topic":"MENSURATION : LENGTHS AND PERIMETERS","question":"A bicycle wheel of radius 42cm is rolled over a distance of 66 meters. how many revolutions does it make?","images":[],"options":{"A":"2.5","B":"5","C":"25","D":"50"},"answer":"C","explanation":"Radius of wheel = 42cm  Circumference of the bicycle wheel = 2\u03c0r  =2x227x42=264cm = 2.64m  Numberofrevolution=662.64=25","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>42","subject":"Mathematics","year":"2000","type":"Objective","topic":"MENSURATION : VOLUMES","question":"The height of a pyramid on a square base is 15cm. if the volume is 80cm3, find the area of the square base","images":[],"options":{"A":"8cm2","B":"9.6cm2","C":"16cm2","D":"25cm2"},"answer":"C","explanation":"Volumeofpyramid=13basearea\u00d7height  Let the b area of base = A  13A\u00d7h=80  13\u00d7A\u00d715=80  5A = 80  A = 16cm2","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>43","subject":"Mathematics","year":"2000","type":"Objective","topic":"MENSURATION : VOLUMES","question":"A tap leaks at the rate of 2cm3 per second . how long will it take the tap to fill a container of 45 litres capacity ?(1 litre = 1000cm3)","images":[],"options":{"A":"8 hour","B":"6 hour 15 minutes","C":"4 hour 25 minutes","D":"3 hour"},"answer":"B","explanation":"Total capacity of the container   \u21d2 45 liters  \u21d2 45 \u00d7 1000 = 45000cm2  Timetofillcontainer=45,0002 = 22,5000 seconds   =225003600(convertingtohours)  \u21d2 6hr 15mins","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>44","subject":"Mathematics","year":"2000","type":"Objective","topic":"MENSURATION : AREAS","question":"The length of the parallel sides of trapezium are 5cm and 7cm. if its area is 120cm2. find the perpendicular distance between the parallel distance between the parallel side.","images":[],"options":{"A":"5.0 cm","B":"6.9 cm","C":"10.0cm","D":"20.0cm"},"answer":"D","explanation":"Area=12(a+b)h  =12(5+7)h=120  6h = 120  h = 20.0cm","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>45","subject":"Mathematics","year":"2000","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"The arc of  a circle 50cm long, subtend an angle of 75\u2218 at the center of th circle. find the correct to 3 significant figure, radius of the circle.","images":[],"options":{"A":"8.74cm","B":"38.2cm","C":"61.2cm","D":"76.4cm"},"answer":"B","explanation":"Lengthofarc=\u03b8360\u00d72\u03c0r  50=75360\u00d721\u00d7227\u00d7r  r=50 x 360 x 775 x 2 x 22  =42011 = 38.18cm  \u2248 38.2 (in 3 sig)","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2000>46","subject":"Mathematics","year":"2000","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"In the diagram, |PQ| = |PS| and |RQ| = |RS| which of the following statement is true?","images":["data:image/png;base64,"],"options":{"A":"","B":"|PO| = |RO|","C":"QR||PS","D":""},"answer":"D","explanation":"|PQ| = |PS|  |RQ| = |RS|  \u0394PQR = PSR  Therefore,","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>47","subject":"Mathematics","year":"2000","type":"Objective","topic":"MENSURATION : AREAS","question":"The area of a circle is 38.5cm2. find the diameter [take \u03c0 = 22/7]","images":[],"options":{"A":"22cm","B":"14cm","C":"7cm","D":"6cm"},"answer":"C","explanation":"\u03c0r2 = 38.5   r2=38.5\u00f7227  r2=38.5 \u00d7 722  r = &radic;12.55&nbsp; = 3.5    Diameter = 2r = 2 \u00d7 3.5 = 7cm","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>48","subject":"Mathematics","year":"2000","type":"Objective","topic":"MENSURATION : VOLUMES","question":"Find the volume (in cm3) of the solid shown below","images":["data:image/png;base64,"],"options":{"A":"100cm3","B":"150cm3","C":"175cm3","D":"250cm3"},"answer":"C","explanation":"Volume = Volume of block A + Volume of block B  \u21d2 (5 \u00d7 5 \u00d7 5)cm3 + (5 \u00d7 5 \u00d7 2)cm3 = 175cm3","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>49","subject":"Mathematics","year":"2000","type":"Objective","topic":"ALGEBRAIC PROCESSES : QUADRATIC EQUATIONS","question":"Solve the equation 3 + 5x -2x2 = 0","images":[],"options":{"A":"-1/2, -3","B":"2,3","C":"-2,3","D":"-1/2,3"},"answer":"D","explanation":"3 + 5x - 2x2 = 0  (1 + 2x)(3 - x) = 0  therefore,  1 + 2x = 0 or 3 - x = 0  2x = -1; x = -1/2  3 - x = 0; x = 3","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2000>50","subject":"Mathematics","year":"2000","type":"Objective","topic":"NUMBER AND NUMERATION : SIMPLE INTEREST AND COMPOUND INTEREST","question":"If the simple interest on \u20a62,000 after 9 month is \u20a660, at what rate per annum is the interest charged","images":[],"options":{"A":"2 1/4%","B":"4%","C":"5%","D":"6%"},"answer":"B","explanation":"I=PRT100  60=2000 x R x 9/12100  60=20R\u00d734  24 = 6R  R = 4 = 4%","marks":"1","difficulty":"1"}];